import { Card, CardContent, CardHeader, IconButton, Typography} from '@material-ui/core'
import { MoreVert, Notes } from '@material-ui/icons'
import React from 'react'

export default function SubjectCards({ subject }) {
  return (
    <div>
        <Card>
            <CardHeader 
              action={
                <IconButton>
                  <MoreVert/>
                </IconButton>
              }
              title = {subject.title}
              subheader = {subject.author}
            />
            <CardContent>
              <Typography>
                {subject.body}
              </Typography>
            </CardContent>
        </Card>
    </div>
  )
}
